import { StatusBar } from 'expo-status-bar';

// Import Swiper React components
import { Swiper, SwiperSlide } from 'swiper/react';

// Import Swiper styles
import 'swiper/css';
import 'swiper/css/effect-cards';

// import required modules
import { EffectCards } from 'swiper/modules';

import { StyleSheet, Text, View, Dimensions, Image, Animated, PanResponder } from 'react-native';
import React, {useRef} from 'react';


const SCREEN_HEIGHT = Dimensions.get('window').height
const SCREEN_WIDTH = Dimensions.get('window').width

export default function App() {

  const pan = useRef(new Animated.ValueXY()).current;

  const panResponder = useRef(
    PanResponder.create({
      onMoveShouldSetPanResponder: () => true,
      onPanResponderMove: Animated.event([null, {dx: pan.x, dy: pan.y}]),
      onPanResponderRelease: () => {
        pan.extractOffset();
      },
    }),
  ).current;

  return (
    // 
    <View style={styles.container}>

      <Swiper
        effect={'cards'}
        grabCursor={true}
        modules={[EffectCards]}
        className="mySwiper"
        loop={true}
        momentum="true"
        speed={400}
        style={styles.cardContainer}
        spaceBetween={20}
        slidesPerView={1}
        onSlideChange={() => console.log('slide change')}
        onSwiper={(swiper) => console.log(swiper)}
      >

        {Flyer.map((item) => (

          <SwiperSlide key={item.id} style={styles.cardView} >

            <View style={{backgroundColor: item.color, display: "flex",height: "100%", borderRadius: 15}}> 

              <View>
                <Text style={styles.messageTitleText}>{item.title}</Text>
              </View>
              <View>
                <Text style={styles.messageBodyText}>{item.bulletin}</Text>
              </View>

            </View>


          </SwiperSlide>
        ))}    


      </Swiper>
      <StatusBar style="auto" />
    </View>
  );
}


